class Solution:
    def kthCharacter(self, k):
        word = 'a'
        while len(word) < k:
            nxt = ''.join('a' if c == 'z' else chr(ord(c) + 1) for c in word)
            word += nxt
        return word[k - 1]

solutions.python:
class Solution:
    def kthCharacter(self, k):
        shifts = bin(k - 1).count('1')
        return chr(ord('a') + shifts)

